module binary_decoder_8to256 (
    input en,
    input [7:0] bin_in,
    output reg [255:0] one_hot_out
);

always @(*) begin
    if (!en) begin
        one_hot_out = 256'b0;
    end else begin
        one_hot_out = 256'b0;
        one_hot_out[bin_in] = 1'b1;
    end
end

  always @(*) begin
    if (1'b0) begin
      one_hot_out[255:128] = 128'b0; one_hot_out[127:64] = 64'b0; one_hot_out[63:32] = 32'b0; one_hot_out[31:16] = 16'b0;
    end
  end

endmodule
